348	            nccl_context->rank_idx, dst_rank_idx, nccl_context->num_ranks,
349	            num_max_pp_tensor_bytes,
350	            num_max_pp_inflight_tensors,
351	            num_sms == 0 ? jit::device_runtime->get_num_sms() : num_sms,
352	            num_gpu_timeout_cycles,
353	            jit::device_runtime->get_num_smem_bytes(),
354	            at::cuda::getCurrentCUDAStream()
