399	    void destroy_agrs_session() {
400	        // Must be in a session
401	        EP_HOST_ASSERT(agrs_in_session);
402	        agrs_in_session = false;
403	
404	        // Wait compute stream
405	        stream_wait(comm_stream, at::cuda::getCurrentCUDAStream());
406	
407	        // Notify that the buffer is now available & Wait for the buffer to be ready
408	        // NOTES: self-wait is guaranteed by in-stream order
409	        std::vector<void*> write_ptrs(nccl_context->num_ranks - 1);
410	        std::vector<void*> wait_ptrs(nccl_context->num_ranks - 1);
411	        for (int i = 0; i < nccl_context->num_ranks - 1; ++ i) {
412	            const auto dst_rank_idx = (nccl_context->rank_idx + i + 1) % nccl_context->num_ranks;
413	            write_ptrs[i] = static_cast<int*>(
414	                nccl_context->get_sym_ptr(workspace_layout_wo_expert->get_agrs_session_signal_ptr(nccl_context->rank_idx), dst_rank_idx));
415	            wait_ptrs[i] = workspace_layout_wo_expert->get_agrs_session_signal_ptr(dst_rank_idx);
416	        }
417	        cuda_driver::batched_write_and_wait(comm_stream, write_ptrs, wait_ptrs, agrs_session_idx);
418	    }
