898	                EP_HOST_ASSERT(dst_buffer_slot_idx.is_cuda() and dst_buffer_slot_idx.is_contiguous());
899	                EP_HOST_ASSERT(dst_buffer_slot_idx.scalar_type() == torch::kInt);
900	            } else {
901	                dst_buffer_slot_idx = torch::empty(
902	                    {num_channels, nccl_context->num_scaleout_ranks, num_max_tokens_per_channel, num_topk},
903	                    torch::TensorOptions().device(torch::kCUDA).dtype(torch::kInt)
904	                );
905	            }
906	
907	            // The token metadata during forward
908	            // `[i, j]` means: in channel i, the j-th forwarded token's metadata
909	            // Info contains:
910	            //   - Scaleout rank index and source token index in the original rank (0)
911	            //   - Whether the token is the last one in the chunk (1)
912	            //   - cached top-k scaleup peer indices (top-k)
913	            //   - each selections' destination slot indices (top-k)
914	            const auto num_max_forwarded_tokens = nccl_context->num_scaleout_ranks * num_max_tokens_per_channel + 1;
915	            const auto num_forward_metadata_dims = 2 + num_topk * 2;
916	            if (cached_mode) {
917	                token_metadata_at_forward = cached_token_metadata_at_forward;
918	                const auto [num_channels_, num_max_forwarded_tokens_, num_forward_metadata_dims_] = get_shape<3>(token_metadata_at_forward.value());
919	                EP_HOST_ASSERT(num_channels == num_channels_ and num_max_forwarded_tokens == num_max_forwarded_tokens_
920	                               and num_forward_metadata_dims == num_forward_metadata_dims_);
921	                EP_HOST_ASSERT(token_metadata_at_forward->is_cuda() and token_metadata_at_forward->is_contiguous());
922	                EP_HOST_ASSERT(token_metadata_at_forward->scalar_type() == torch::kInt);
923	            } else {
924	                token_metadata_at_forward = torch::empty(
925	                    {num_channels, num_max_forwarded_tokens, num_forward_metadata_dims},
926	                    torch::TensorOptions().device(torch::kCUDA).dtype(torch::kInt)
927	                );
928	            }
929	            token_metadata_at_forward_ptr = token_metadata_at_forward->data_ptr<int>();
930	
931	            // Per-scaleup-peer-per-channel linked list
932	            // `[i, j, k]` means: from channel i from scaleup peer k, the j-th token's index in the combine's input
933	            if (cached_mode) {
934	                channel_linked_list = cached_channel_linked_list;
935	                const auto [num_channels__, d1_, d2_] = get_shape<3>(channel_linked_list.value());
