1051	                    }
1052	                    return ss.str();
1053	                };
1054	                if (ready) {
1055	                    if (get_env<int>("EP_BUFFER_DEBUG"))
1056	                        printf("%s\n", get_buffer_info().c_str());
1057	                    break;
1058	                }
1059	
1060	                // Timeout checks
1061	                const auto now = std::chrono::high_resolution_clock::now();
1062	                if (std::chrono::duration_cast<std::chrono::seconds>(now - start_cpu_time).count() > num_cpu_timeout_secs)
1063	                    throw EPExceptionWithLineInfo("Dispatch CPU wait", get_buffer_info());
1064	            }
1065	        } else {
1066	            // Non-cached mode without CPU sync, allocate with the worst case
1067	            num_recv_tokens = num_max_tokens_per_rank * nccl_context->num_ranks;
1068	            num_expanded_tokens = nccl_context->num_ranks * num_max_tokens_per_rank * std::min(num_topk, num_local_experts);
