1120	                psum_num_recv_tokens_per_expert = psum_num_recv_tokens_per_expert.slice(0, 1, num_local_experts + 1);
1121	            }
1122	        }
1123	        EP_HOST_ASSERT(psum_num_recv_tokens_per_expert.size(0) == num_local_experts);
1124	
1125	        // Launch copy kernels with full SMs
1126	        stream_control_before_epilogue(previous_event_before_epilogue);
1127	        launch_dispatch_copy_epilogue(buffer, workspace,
1128	                                      psum_num_recv_tokens_per_scaleup_rank.data_ptr<int>(),
1129	                                      psum_num_recv_tokens_per_expert.data_ptr<int>(),
1130	                                      recv_x.data_ptr(), recv_sf_ptr,
1131	                                      recv_topk_idx_ptr, recv_topk_weights_ptr,
1132	                                      recv_src_metadata.data_ptr<int>(),
1133	                                      channel_linked_list_ptr,
1134	                                      num_unaligned_recv_tokens_per_expert_ptr,
1135	                                      num_recv_tokens, num_max_tokens_per_rank,
1136	                                      num_hidden_bytes,
1137	                                      num_sf_packs, recv_sf_token_stride, recv_sf_hidden_stride,
1138	                                      num_experts, num_topk, expert_alignment,
